ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?tool_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasTools ?child ; p:hasTraffic_Engineers ?parent . } GROUP BY ?child }
  ?child p:name ?tool_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Traffic_Engineers } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?tool_name WHERE {
  ?traffic_engineers_tools a :Traffic_Engineers_Tools .
  ?tools a :Tools .
  ?traffic_engineers_tools p:hasTools ?tools .
  ?traffic_engineers a :Traffic_Engineers .
  ?traffic_engineers_tools p:hasTraffic_Engineers ?traffic_engineers .
  ?traffic_engineers p:name ?name .
  ?tools p:name ?tool_name .
} }
}

